CREATE TABLE "countries" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "country_code" varchar(10) UNIQUE NOT NULL,
  "country_name" varchar(100) NOT NULL,
  "admin_level_1_label" varchar(50) NOT NULL,
  "admin_level_2_label" varchar(50) NOT NULL,
  "phone_code" varchar(10) NOT NULL,
  "currency_code" varchar(10) NOT NULL,
  "timezone" varchar(50) NOT NULL,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "admin_level_1" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "country_id" integer NOT NULL,
  "name" varchar(100) NOT NULL,
  "code" varchar(20),
  "is_active" boolean DEFAULT true
);

CREATE TABLE "admin_level_2" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "admin_level_1_id" integer NOT NULL,
  "name" varchar(100) NOT NULL,
  "is_active" boolean DEFAULT true
);

CREATE TABLE "departments" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(100) NOT NULL,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "brands" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(100) NOT NULL,
  "department_id" integer NOT NULL,
  "niche_id" integer NOT NULL,
  "is_active" boolean DEFAULT true
);

CREATE TABLE "niches" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(100) NOT NULL,
  "is_active" boolean DEFAULT true
);

CREATE TABLE "order_sources" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(100) NOT NULL,
  "is_active" boolean DEFAULT true
);

CREATE TABLE "shipping_types" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(100) NOT NULL,
  "is_active" boolean DEFAULT true
);

CREATE TABLE "expense_categories" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(100) UNIQUE NOT NULL,
  "is_system_reserved" boolean DEFAULT false,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "products" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(200) NOT NULL,
  "department_id" integer NOT NULL,
  "brand_id" integer NOT NULL,
  "type" varchar(50) NOT NULL,
  "category" varchar(100),
  "sku" varchar(100) UNIQUE,
  "price" decimal(12,2) NOT NULL,
  "status" varchar(50) NOT NULL DEFAULT 'Active',
  "description" text,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "product_variants" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "product_id" integer NOT NULL,
  "colour" varchar(100) NOT NULL,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "inventory" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "product_id" integer NOT NULL,
  "variant_id" integer,
  "waybill_stock" integer NOT NULL DEFAULT 0,
  "reserved" integer NOT NULL DEFAULT 0,
  "decremented" integer NOT NULL DEFAULT 0,
  "available" integer NOT NULL,
  "batch" varchar(100),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "order_bump_inventory" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "product_id" integer NOT NULL,
  "variant_id" integer,
  "waybill_stock" integer NOT NULL DEFAULT 0,
  "reserved" integer NOT NULL DEFAULT 0,
  "decremented" integer NOT NULL DEFAULT 0,
  "available" integer NOT NULL,
  "batch" varchar(100),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "roles" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(100) UNIQUE NOT NULL,
  "description" text,
  "can_edit_orders" boolean DEFAULT false,
  "can_delete_orders" boolean DEFAULT false,
  "can_view_finance" boolean DEFAULT false,
  "can_view_payroll" boolean DEFAULT false,
  "can_export_csv" boolean DEFAULT false,
  "can_manage_users" boolean DEFAULT false,
  "is_active" boolean DEFAULT true
);

CREATE TABLE "users" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "role_id" integer NOT NULL,
  "username" varchar(100) UNIQUE NOT NULL,
  "display_name" varchar(100) NOT NULL,
  "full_name" varchar(200) NOT NULL,
  "email" varchar(200) UNIQUE NOT NULL,
  "phone" varchar(20),
  "password_hash" varchar(255) NOT NULL,
  "is_active" boolean DEFAULT true,
  "two_fa_enabled" boolean DEFAULT false,
  "two_fa_secret" varchar(255),
  "trusted_device_expires_at" timestamp,
  "last_login_at" timestamp,
  "last_logout_at" timestamp,
  "csr_level" integer DEFAULT 1,
  "is_on_break" boolean DEFAULT false,
  "created_by" integer,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "user_departments" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" integer NOT NULL,
  "department_id" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "employee_profiles" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" integer UNIQUE NOT NULL,
  "date_of_birth" date,
  "date_of_employment" date,
  "contact_address" text,
  "gender" varchar(20),
  "marital_status" varchar(50),
  "nationality" varchar(100),
  "state_of_origin" varchar(100),
  "lga_of_origin" varchar(100),
  "languages_spoken" varchar(200),
  "nin" varchar(255),
  "drivers_license" varchar(100),
  "tax_id" varchar(100),
  "next_of_kin_name" varchar(200),
  "next_of_kin_relationship" varchar(100),
  "next_of_kin_phone" varchar(20),
  "next_of_kin_address" text,
  "emergency_contact_name" varchar(200),
  "emergency_contact_relationship" varchar(100),
  "emergency_contact_phone_1" varchar(20),
  "emergency_contact_phone_2" varchar(20),
  "emergency_contact_address" text,
  "medical_conditions" text,
  "main_bank_name" varchar(100),
  "main_account_number" varchar(255),
  "main_account_type" varchar(50),
  "alternate_bank_name" varchar(100),
  "alternate_account_number" varchar(255),
  "alternate_account_type" varchar(50),
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "session_log" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" integer NOT NULL,
  "logged_in_at" timestamp NOT NULL,
  "logged_out_at" timestamp,
  "session_duration_minutes" integer,
  "last_active_at" timestamp,
  "ip_address" varchar(50),
  "device_info" text
);

CREATE TABLE "customers" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "phone_number" varchar(20) UNIQUE NOT NULL,
  "other_phone" varchar(20),
  "full_name" varchar(200),
  "email" varchar(200),
  "sex" varchar(20),
  "first_order_date" timestamp,
  "last_order_date" timestamp,
  "total_orders" integer DEFAULT 0,
  "total_purchases" integer DEFAULT 0,
  "lifetime_value" decimal(14,2) DEFAULT 0,
  "customer_tag" varchar(50) DEFAULT 'new',
  "is_banned" boolean DEFAULT false,
  "ban_reason" text,
  "banned_at" timestamp,
  "banned_by" integer,
  "csr_notes" text,
  "wati_opted_out" boolean DEFAULT false,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "agents" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(200) NOT NULL,
  "contact_name" varchar(200),
  "phone" varchar(20),
  "email" varchar(200),
  "address" text,
  "city" varchar(100),
  "admin_level_1_id" integer,
  "admin_level_2_id" integer,
  "bank_name" varchar(100),
  "account_number" varchar(50),
  "account_name" varchar(200),
  "status" varchar(50) DEFAULT 'Active',
  "ratings" decimal(3,1),
  "restrictions" text,
  "source" varchar(200),
  "whatsapp_group_name" varchar(200),
  "whatsapp_group_link" varchar(255),
  "comments" text,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "agent_zone_assignments" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "admin_level_1_id" integer NOT NULL,
  "admin_level_2_id" integer,
  "primary_agent_id" integer NOT NULL,
  "overflow_agent_id" integer,
  "dispatch_rule" varchar(50) NOT NULL DEFAULT 'direct_assign',
  "zone_belt" varchar(100),
  "notes" text,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "orders" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "order_id" varchar(100) UNIQUE NOT NULL,
  "row_number" integer,
  "ordered_at" timestamp NOT NULL,
  "order_time" varchar(20),
  "scheduled_date" date,
  "date_paid" date,
  "first_contact_at" timestamp,
  "source_id" integer,
  "assigned_csr_id" integer NOT NULL,
  "department_id" integer NOT NULL,
  "brand_id" integer,
  "country_id" integer NOT NULL DEFAULT 1,
  "customer_id" integer,
  "customer_name" varchar(200) NOT NULL,
  "phone_number" varchar(20) NOT NULL,
  "other_phone" varchar(20),
  "email" varchar(200),
  "sex" varchar(20),
  "is_return_customer" boolean DEFAULT false,
  "admin_level_1_id" integer,
  "admin_level_2_id" integer,
  "city" varchar(200),
  "full_address" text,
  "status" varchar(100) NOT NULL DEFAULT 'Interested',
  "comments" text,
  "failure_reason_id" integer,
  "product_id" integer NOT NULL,
  "product_variant_id" integer,
  "quantity" integer NOT NULL DEFAULT 1,
  "price" decimal(12,2) NOT NULL,
  "currency_code" varchar(10) DEFAULT 'NGN',
  "has_order_bump" boolean DEFAULT false,
  "order_bump_product_id" integer,
  "order_bump_variant_id" integer,
  "order_bump_quantity" integer DEFAULT 0,
  "order_bump_price" decimal(12,2) DEFAULT 0,
  "order_bump_type" varchar(100),
  "agent_id" integer,
  "logistics_fee" decimal(12,2),
  "shipping_type_id" integer,
  "niche_id" integer,
  "wati_sequence_triggered" boolean DEFAULT false,
  "wati_suppressed" boolean DEFAULT false,
  "api_batch_id" varchar(100),
  "late_cash_paid" boolean DEFAULT false,
  "is_test" boolean DEFAULT false,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "order_id_counter" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "prefix" varchar(20) NOT NULL DEFAULT 'CJAM',
  "last_number" integer NOT NULL DEFAULT 999,
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "order_status_history" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "order_id" integer NOT NULL,
  "previous_status" varchar(100),
  "new_status" varchar(100) NOT NULL,
  "changed_by" integer NOT NULL,
  "changed_at" timestamp DEFAULT (now()),
  "notes" text
);

CREATE TABLE "audit_log" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" integer NOT NULL,
  "action" varchar(100) NOT NULL,
  "table_name" varchar(100),
  "record_id" integer,
  "old_value" text,
  "new_value" text,
  "ip_address" varchar(50),
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "agent_remittance" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "agent_id" integer NOT NULL,
  "admin_level_1_id" integer,
  "amount_remitted" decimal(14,2) NOT NULL,
  "logistics_fee_paid" decimal(14,2) DEFAULT 0,
  "final_amount_remitted" decimal(14,2) NOT NULL,
  "remittance_date" date NOT NULL,
  "currency_code" varchar(10) DEFAULT 'NGN',
  "status" varchar(50) NOT NULL DEFAULT 'Pending_Bank_Verification',
  "logged_by" integer NOT NULL,
  "verified_by" integer,
  "verified_at" timestamp,
  "bank_reference" varchar(200),
  "actual_amount_received" decimal(14,2),
  "variance_amount" decimal(14,2),
  "variance_reason_id" integer,
  "dispute_notes" text,
  "month" varchar(20),
  "year" integer,
  "comments" text,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "expenses" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "expense_category_id" integer NOT NULL,
  "description" text,
  "amount" decimal(14,2) NOT NULL,
  "expense_date" date NOT NULL,
  "currency_code" varchar(10) DEFAULT 'NGN',
  "month" varchar(20),
  "year" integer,
  "product_id" integer,
  "agent_id" integer,
  "admin_level_1_id" integer,
  "batch" varchar(100),
  "comments" text,
  "receipt_url" varchar(500),
  "logged_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "procurement_expenses" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "description" text NOT NULL,
  "vendor_id" integer,
  "product_id" integer,
  "batch" varchar(100),
  "unit_quantity" integer NOT NULL,
  "unit_price_usd" decimal(10,4) NOT NULL,
  "shipping_usd" decimal(10,2) DEFAULT 0,
  "processing_fee_usd" decimal(10,2) DEFAULT 0,
  "alibaba_cut" decimal(10,4) DEFAULT 0,
  "total_usd" decimal(10,2) NOT NULL,
  "exchange_rate" decimal(10,2) NOT NULL,
  "total_ngn" decimal(14,2) NOT NULL,
  "procurement_date" date NOT NULL,
  "month" varchar(20),
  "year" integer,
  "niche_id" integer,
  "comments" text,
  "receipt_url" varchar(500),
  "logged_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "ad_expenses" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "product_id" integer,
  "brand_id" integer,
  "campaign_name" varchar(200),
  "time_period" varchar(100),
  "amount" decimal(14,2) NOT NULL,
  "platform" varchar(50),
  "payment_method" varchar(100),
  "expense_date" date NOT NULL,
  "month" varchar(20),
  "year" integer,
  "comments" text,
  "receipt_url" varchar(500),
  "logged_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "investment_inflow" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "amount" decimal(14,2) NOT NULL,
  "inflow_date" date NOT NULL,
  "currency_code" varchar(10) DEFAULT 'NGN',
  "month" varchar(20),
  "year" integer,
  "comments" text,
  "logged_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "loans" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "amount" decimal(14,2) NOT NULL,
  "loan_date" date NOT NULL,
  "currency_code" varchar(10) DEFAULT 'NGN',
  "lender" varchar(200),
  "repayment_status" varchar(50) DEFAULT 'Outstanding',
  "amount_repaid" decimal(14,2) DEFAULT 0,
  "due_date" date,
  "month" varchar(20),
  "year" integer,
  "comments" text,
  "logged_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "payroll" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" integer NOT NULL,
  "amount" decimal(14,2) NOT NULL,
  "commission_amount" decimal(12,2) DEFAULT 0,
  "total_compensation" decimal(12,2),
  "payment_date" date,
  "currency_code" varchar(10) DEFAULT 'NGN',
  "month" varchar(20),
  "year" integer,
  "payment_method" varchar(100),
  "bank_name" varchar(100),
  "account_number" varchar(50),
  "bank_reference" varchar(200),
  "status" varchar(50) DEFAULT 'Pending_Director_Approval',
  "director_approved_by" integer,
  "director_approved_at" timestamp,
  "comments" text,
  "logged_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "taxes" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "tax_type" varchar(100) NOT NULL,
  "amount" decimal(14,2) NOT NULL,
  "tax_date" date NOT NULL,
  "currency_code" varchar(10) DEFAULT 'NGN',
  "month" varchar(20),
  "year" integer,
  "comments" text,
  "receipt_url" varchar(500),
  "logged_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "goods_movement" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "product_id" integer NOT NULL,
  "variant_id" integer,
  "quantity" integer NOT NULL,
  "movement_type" varchar(50) NOT NULL,
  "from_agent_id" integer,
  "to_agent_id" integer,
  "admin_level_1_id" integer,
  "shipping_type_id" integer,
  "movement_date" date NOT NULL,
  "batch" varchar(100),
  "month" varchar(20),
  "year" integer,
  "comments" text,
  "logged_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "complaints" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "order_id" integer NOT NULL,
  "customer_id" integer NOT NULL,
  "assigned_csr_id" integer,
  "complaint_type" varchar(100),
  "description" text NOT NULL,
  "resolution" text,
  "refund_amount" decimal(12,2) DEFAULT 0,
  "date_of_complaint" date,
  "replaced_or_refunded" boolean DEFAULT false,
  "cost_of_return" decimal(12,2) DEFAULT 0,
  "total_cost" decimal(12,2),
  "date_of_return" date,
  "status" varchar(50) DEFAULT 'Open',
  "logged_at" timestamp DEFAULT (now()),
  "resolved_at" timestamp,
  "resolved_by" integer,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "trashed_items" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "product_id" integer NOT NULL,
  "variant_id" integer,
  "quantity" integer NOT NULL,
  "agent_id" integer NOT NULL,
  "admin_level_1_id" integer,
  "status" varchar(50) NOT NULL DEFAULT 'Trashed',
  "month" varchar(20),
  "year" integer,
  "comments" text,
  "logged_by" integer NOT NULL,
  "logged_at" date NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "notifications" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "notification_type" varchar(100) NOT NULL,
  "channel" varchar(50) NOT NULL,
  "recipient_type" varchar(50) NOT NULL,
  "recipient_user_id" integer,
  "recipient_agent_id" integer,
  "subject" varchar(200),
  "message" text,
  "status" varchar(50) DEFAULT 'Sent',
  "sent_at" timestamp DEFAULT (now()),
  "error_message" text
);

CREATE TABLE "waybill_expenses" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "waybill_type" varchar(50) NOT NULL,
  "product_id" integer,
  "variant_id" integer,
  "quantity" integer,
  "batch" varchar(100),
  "colour" varchar(100),
  "waybill_status" varchar(50),
  "product_type" varchar(20),
  "from_admin_level_1_id" integer,
  "to_admin_level_1_id" integer,
  "agent_id" integer,
  "amount" decimal(14,2) NOT NULL,
  "currency_code" varchar(10) DEFAULT 'NGN',
  "courier" varchar(100),
  "waybill_date" date NOT NULL,
  "payment_method" varchar(100),
  "month" varchar(20),
  "year" integer,
  "comments" text,
  "receipt_url" varchar(500),
  "logged_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "action_items" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "title" varchar(200) NOT NULL,
  "description" text,
  "assigned_to" integer,
  "assigned_by" integer,
  "status" varchar(50) DEFAULT 'Open',
  "priority" varchar(50) DEFAULT 'Medium',
  "due_date" date,
  "closed_at" timestamp,
  "closed_by" integer,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "csr_levels" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "level_number" integer NOT NULL,
  "level_name" varchar(50) NOT NULL,
  "base_salary" decimal(12,2) NOT NULL,
  "description" text,
  "is_active" boolean DEFAULT true
);

CREATE TABLE "commission_tiers" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "department_id" integer NOT NULL,
  "payment_rate_min" decimal(5,2) NOT NULL,
  "payment_rate_max" decimal(5,2),
  "commission_per_unit" decimal(10,2) NOT NULL,
  "is_active" boolean DEFAULT true,
  "notes" text
);

CREATE TABLE "csr_promotion_thresholds" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "department_id" integer NOT NULL,
  "from_level" integer NOT NULL,
  "to_level" integer NOT NULL,
  "direction" varchar(10) NOT NULL,
  "payment_rate_threshold" decimal(5,2) NOT NULL,
  "consecutive_months_required" integer NOT NULL,
  "is_active" boolean DEFAULT true
);

CREATE TABLE "csr_level_history" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" integer NOT NULL,
  "previous_level" integer,
  "new_level" integer NOT NULL,
  "changed_at" timestamp DEFAULT (now()),
  "changed_by" integer,
  "reason" text
);

CREATE TABLE "csr_performance_monthly" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" integer NOT NULL,
  "department_id" integer NOT NULL,
  "month" varchar(20) NOT NULL,
  "year" integer NOT NULL,
  "total_orders" integer DEFAULT 0,
  "total_units_ordered" integer DEFAULT 0,
  "total_units_paid" integer DEFAULT 0,
  "payment_rate" decimal(5,2) DEFAULT 0,
  "commission_tier_id" integer,
  "commission_per_unit" decimal(10,2) DEFAULT 0,
  "total_commission" decimal(12,2) DEFAULT 0,
  "base_salary" decimal(12,2) DEFAULT 0,
  "total_compensation" decimal(12,2) DEFAULT 0,
  "csr_level_at_time" integer,
  "is_finalised" boolean DEFAULT false,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "weekly_bonus_log" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "user_id" integer NOT NULL,
  "week_start_date" date NOT NULL,
  "week_end_date" date NOT NULL,
  "payment_rate_achieved" decimal(5,2) NOT NULL,
  "bonus_amount" decimal(10,2) NOT NULL DEFAULT 10000,
