  "paid_by" integer,
  "notes" text,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "failure_reason_codes" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "code" varchar(50) UNIQUE NOT NULL,
