  "reviewed_by" integer,
  "reviewed_at" timestamp,
  "notes" text,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "backup_log" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "backup_type" varchar(50) NOT NULL,
  "file_name" varchar(200),
  "file_size_mb" decimal(8,2),
  "status" varchar(50) NOT NULL,
  "started_at" timestamp NOT NULL,
  "completed_at" timestamp,
  "error_message" text,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "wati_export_log" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "export_type" varchar(50) NOT NULL,
  "export_date" date NOT NULL,
  "records_exported" integer NOT NULL,
  "status" varchar(50) NOT NULL,
  "error_message" text,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "stock_adjustments" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "product_id" integer NOT NULL,
  "variant_id" integer,
  "quantity_adjusted" integer NOT NULL,
  "adjustment_type" varchar(100) NOT NULL,
  "comments" text NOT NULL,
  "logged_by" integer NOT NULL,
  "approved_by" integer,
  "approved_at" timestamp,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "agent_ledger" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "agent_id" integer NOT NULL,
  "transaction_type" varchar(100) NOT NULL,
  "reference_id" integer,
  "reference_table" varchar(100),
  "debit_amount" decimal(14,2) DEFAULT 0,
  "credit_amount" decimal(14,2) DEFAULT 0,
  "running_balance" decimal(14,2) NOT NULL,
  "currency_code" varchar(10) DEFAULT 'NGN',
  "notes" text,
  "logged_by" integer,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "department_targets" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "department_id" integer NOT NULL,
  "base_conversion_rate" decimal(5,2) NOT NULL,
  "target_conversion_rate" decimal(5,2) NOT NULL,
  "planned_sales_rate" decimal(5,2) NOT NULL DEFAULT 70,
  "effective_from" date NOT NULL,
  "set_by" integer NOT NULL,
  "notes" text,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "vendors" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(200) NOT NULL,
  "vendor_type" varchar(100),
  "phone_1" varchar(20),
  "phone_2" varchar(20),
  "address" text,
  "city" varchar(100),
  "admin_level_1_id" integer,
  "admin_level_2_id" integer,
  "country_id" integer,
  "comments" text,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "lesson_categories" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "name" varchar(100) UNIQUE NOT NULL,
  "is_active" boolean DEFAULT true,
  "created_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "lessons_learned" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "title" varchar(300) NOT NULL,
  "content" text NOT NULL,
  "category_id" integer NOT NULL,
  "submitted_by" integer NOT NULL,
  "status" varchar(50) NOT NULL DEFAULT 'Pending',
  "rejection_reason" text,
  "reviewed_by" integer,
  "reviewed_at" timestamp,
  "published_at" timestamp,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now()),
  "updated_at" timestamp DEFAULT (now())
);

CREATE TABLE "escalation_reason_codes" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "code" varchar(100) UNIQUE NOT NULL,
  "description" varchar(200) NOT NULL,
  "is_active" boolean DEFAULT true,
  "created_by" integer NOT NULL,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "order_escalations" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "order_id" integer NOT NULL,
  "reason_code_id" integer NOT NULL,
  "raised_by" integer NOT NULL,
  "raised_at" timestamp DEFAULT (now()),
  "csr_notes" text NOT NULL,
  "status" varchar(50) NOT NULL DEFAULT 'Open',
  "resolved_by" integer,
  "resolved_at" timestamp,
  "resolution_action" varchar(100),
  "resolution_notes" text,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "remittance_variance_reason_codes" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "code" varchar(100) UNIQUE NOT NULL,
  "description" varchar(200) NOT NULL,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "auditor_check_categories" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "code" varchar(100) UNIQUE NOT NULL,
  "description" varchar(200) NOT NULL,
  "is_active" boolean DEFAULT true,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "auditor_spot_checks" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "order_id" integer NOT NULL,
  "auditor_id" integer NOT NULL,
  "check_date" date NOT NULL DEFAULT (CURRENT_DATE),
  "check_category_id" integer NOT NULL,
  "result" varchar(50) NOT NULL,
  "auditor_notes" text,
  "escalated_to_director" boolean DEFAULT false,
  "director_reviewed_at" timestamp,
  "created_at" timestamp DEFAULT (now())
);

CREATE TABLE "weekly_reports" (
  "id" INTEGER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  "report_type" varchar(50) NOT NULL,
  "department_id" integer,
  "csr_id" integer,
  "week_start_date" date NOT NULL,
  "week_end_date" date NOT NULL,
  "providus_inflow" decimal(14,2),
  "providus_outflow" decimal(14,2),
  "providus_comments" text,
  "moniepoint_inflow" decimal(14,2),
  "moniepoint_outflow" decimal(14,2),
  "moniepoint_comments" text,
  "accountant_notes" text,
  "cash_flow_logged" boolean DEFAULT false,
  "ops_aob" text,
  "csr_aob" text,
  "generated_by" integer NOT NULL,
  "pdf_url" varchar(500),
  "created_at" timestamp DEFAULT (now())
);

COMMENT ON COLUMN "countries"."country_code" IS 'ISO code e.g. NG, GH, KE';

