COMMENT ON COLUMN "admin_level_1"."code" IS 'e.g. LA for Lagos, AB for Abuja';

COMMENT ON COLUMN "expense_categories"."is_system_reserved" IS 'If true, only automated processes can write to this category. Not shown in manual expense dropdown.';

